import { useState, useEffect } from 'react';
import fire from "../fire"
import BarChart from './BarChart';
import Button from '@material-ui/core/Button'
import Alert from '@material-ui/lab/Alert';
import TableResult from './TableResult';
import { makeStyles } from '@material-ui/core/styles';
import TextField from '@material-ui/core/TextField';
import Grid from '@material-ui/core/Grid';
import SearchIcon from '@material-ui/icons/Search';
import IconButton from '@material-ui/core/IconButton';
import Select from '@material-ui/core/Select';
import FormControl from '@material-ui/core/FormControl';
import MenuItem from '@material-ui/core/MenuItem';
import InputLabel from '@material-ui/core/InputLabel';
const useStyles = makeStyles((theme) => ({
    margin: {
        margin: theme.spacing(1),
    },
    button: {
        margin: theme.spacing(1),
    },
    formControl: {
        margin: theme.spacing(1),
        minWidth: 120,
    },
    selectEmpty: {
        marginTop: theme.spacing(2),
    },
}));



const Search = () => {

    const classes = useStyles();


    const [data, setData] = useState(null);
    const [keywords, setKeywords] = useState('');
    const [country, setCountry] = useState('AU');
    const [url, setUrl] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [chart, setChartSelected] = useState(true);
    const [table, setTableSelected] = useState(false);
    const [error, setError] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');






    useEffect(() => {
        const fetchData = () => {
            setIsLoading(true);
            fetch(url).then(res => {
                return res.json();
            })
                .then(data => {


                    if (!data.status) {
                        setData(data);
                        setError(false);
                        setIsLoading(false);
                    } else {
                        setError(true);
                        setErrorMessage(data.message)
                        setIsLoading(false);
                    }
                })
                .catch(error => {

                    console.log(error)
                })
        }

        if (url !== '') {
            setData(null)
            fetchData();
            setUrl('');
        }



    }, [url, data]);


    const handleKeywords = (event) => {
        setKeywords(event.target.value)
    }
    const handleCountry = (event) => { setCountry(event.target.value) }
    const handleLogout = () => { fire.auth().signOut() }
    const selectChart = () => {
        setChartSelected(true);
        setTableSelected(false);
    }
    const selectTable = () => {
        setTableSelected(true);
        setChartSelected(false);
    }
    const clickSearch = () => {


        if (url !== '') {
            // var url = 'http://localhost:5000/api/chart?keywords=' + keywords + '&country=' + country;
            var url = 'http://localhost:5000/api/test'
            setUrl(url)
        }
    }



    return (

        <div>
            <Button onClick={handleLogout}>Logout</Button>
            <div className={classes.margin}>
                <Grid container spacing={1} alignItems="flex-end">

                    <Grid item>
                        <TextField value={keywords} onChange={handleKeywords} id="input-with-icon-grid" label="Search..." />
                    </Grid>
                    <Grid item>
                        <IconButton disabled={!keywords} onClick={clickSearch}>
                            <SearchIcon></SearchIcon>
                        </IconButton>
                    </Grid>
                    <Grid item2>
                        <FormControl className={classes.formControl}>
                            <InputLabel id="demo-simple-select-label">Country</InputLabel>
                            <Select
                                labelId="demo-simple-select-label"
                                id="demo-simple-select"
                                value={country}
                                onChange={handleCountry}
                            >
                                <MenuItem value={10}>Ten</MenuItem>
                                <MenuItem value={20}>Twenty</MenuItem>
                                <MenuItem value={30}>Thirty</MenuItem>
                            </Select>
                        </FormControl>
                    </Grid>
                </Grid>
            </div>
            <select value={country} onChange={handleCountry}>
                <option defaultValue value="US">United States</option>
                <option value="AU">Australia</option>
                <option value="GB">Great Britain</option>
                <option value="FR">France</option>
            </select>
            {error && <Alert variant="outlined" severity="error" onClose={() => { setError(false) }}>{errorMessage}</Alert>}
            <button disabled={!data} type="button" onClick={selectChart}>
                Bar Chart
            </button>
            <button disabled={!data} type="button" onClick={selectTable}>
                Table Results
            </button>

            {isLoading && <div>Loading...</div>}
            {data && chart && <div style={{ height: "500px", width: "500px" }}><BarChart data={data} /></div>}
            {data && table && <TableResult data={data} />}





        </div>

    );
}

export default Search;
